4	// MARK: - Protocol
5	
6	/// Single source of truth for user-adjustable runtime behaviour.
7	/// Injectable so tests can swap in `InMemoryAppPreferences`.
8	@MainActor
9	public protocol AppPreferences: AnyObject, Observable, Sendable {
10	    var refreshInterval: RefreshInterval { get set }
11	    var launchAtLogin: Bool { get set }
12	    var logLevel: LogLevel { get set }
13	    var menuBarSegments: [MenuBarSegmentConfig] { get set }
14	    /// Tracks whether seeding has already run — distinguishes "fresh install"
15	    /// from "user deleted all segments." False on a brand-new UserDefaults suite.
16	    var menuBarSegmentsInitialized: Bool { get set }
17	    /// String inserted between adjacent segments in the menu bar label. Defaults to " | ".
18	    var menuBarSeparator: String { get set }
19	    /// When true, the menu bar prepends `menuBarOutageWarningText` while at least
20	    /// one vendor has an active outage. Defaults to true (opt-out).
21	    var menuBarOutageWarningEnabled: Bool { get set }
22	    /// Short label rendered before segments while any vendor has an active outage.
23	    /// Defaults to "⚠️".
24	    var menuBarOutageWarningText: String { get set }
25	    var chartConfigurations: [ChartConfiguration] { get set }
26	    /// Tracks whether chart seeding has already run so an intentionally empty
27	    /// configuration list is preserved after first initialization.
28	    var chartConfigurationsInitialized: Bool { get set }
29	    var ignoredAccounts: [IgnoredAccount] { get set }
30	}
31	
32	// MARK: - UserDefaults-backed implementation
33	
34	@Observable
35	@MainActor
36	public final class UserDefaultsAppPreferences: AppPreferences {
37	    private let defaults: UserDefaults
38	
39	    public init(defaults: UserDefaults = .standard) {
40	        self.defaults = defaults
41	    }
42	
43	    public var refreshInterval: RefreshInterval {
44	        get {
45	            access(keyPath: \.refreshInterval)
46	            let raw = defaults.integer(forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
47	            if raw == 0 { return .default }
48	            return RefreshInterval(clamping: raw)
49	        }
50	        set {
51	            withMutation(keyPath: \.refreshInterval) {
52	                defaults.set(newValue.seconds, forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
53	            }
54	        }
55	    }
56	
57	    public var launchAtLogin: Bool {
58	        get {
59	            access(keyPath: \.launchAtLogin)
60	            return defaults.bool(forKey: AppPreferenceKeys.launchAtLogin.rawValue)
61	        }
62	        set {
63	            withMutation(keyPath: \.launchAtLogin) {
64	                defaults.set(newValue, forKey: AppPreferenceKeys.launchAtLogin.rawValue)
65	            }
66	        }
67	    }
68	
69	    public var logLevel: LogLevel {
70	        get {
71	            access(keyPath: \.logLevel)
72	            let raw = defaults.string(forKey: AppPreferenceKeys.logLevel.rawValue) ?? ""
73	            if raw.isEmpty { return .info }
74	            return LogLevel.from(string: raw)
75	        }
76	        set {
77	            withMutation(keyPath: \.logLevel) {
78	                defaults.set(newValue.label.lowercased(), forKey: AppPreferenceKeys.logLevel.rawValue)
79	            }
80	        }
81	    }
82	
83	    public var menuBarSegments: [MenuBarSegmentConfig] {
84	        get {
85	            // @Observable wraps stored properties; computed ones need manual tracking so
86	            // SwiftUI / withObservationTracking observers are notified on mutation.
87	            access(keyPath: \.menuBarSegments)
88	            guard let data = defaults.data(forKey: AppPreferenceKeys.menuBarSegments.rawValue) else {
89	                return []
90	            }
91	            do {
92	                return try JSONDecoder().decode([MenuBarSegmentConfig].self, from: data)
93	            } catch {
94	                Loggers.app.log(.error, "Failed to decode menuBarSegments from UserDefaults: \(error)")
95	                return []
96	            }
97	        }
98	        set {
99	            withMutation(keyPath: \.menuBarSegments) {
100	                do {
101	                    let data = try JSONEncoder().encode(newValue)
102	                    defaults.set(data, forKey: AppPreferenceKeys.menuBarSegments.rawValue)
103	                } catch {
104	                    Loggers.app.log(.error, "Failed to encode menuBarSegments to UserDefaults: \(error)")
105	                }
106	            }
107	        }
108	    }
109	
110	    public var menuBarSegmentsInitialized: Bool {
111	        get { defaults.bool(forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
112	        set { defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
113	    }
114	
115	    public var menuBarSeparator: String {
116	        get {
117	            access(keyPath: \.menuBarSeparator)
118	            let stored = defaults.string(forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
119	            return stored ?? " | "
120	        }
121	        set {
122	            withMutation(keyPath: \.menuBarSeparator) {
123	                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
124	            }
125	        }
126	    }
127	
128	    public var menuBarOutageWarningEnabled: Bool {
129	        get {
130	            access(keyPath: \.menuBarOutageWarningEnabled)
131	            // Default to enabled on a fresh install — but only if we've never persisted
132	            // an explicit value. UserDefaults.bool returns false for missing keys, so we
133	            // gate on a separate "initialized" flag to distinguish "never set" from
134	            // "explicitly disabled".
135	            if !defaults.bool(forKey: AppPreferenceKeys.menuBarOutageWarningEnabledInitialized.rawValue) {
136	                return true
137	            }
138	            return defaults.bool(forKey: AppPreferenceKeys.menuBarOutageWarningEnabled.rawValue)
139	        }
140	        set {
141	            withMutation(keyPath: \.menuBarOutageWarningEnabled) {
142	                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarOutageWarningEnabled.rawValue)
143	                defaults.set(true, forKey: AppPreferenceKeys.menuBarOutageWarningEnabledInitialized.rawValue)
144	            }
145	        }
146	    }
147	
148	    public var menuBarOutageWarningText: String {
149	        get {
150	            access(keyPath: \.menuBarOutageWarningText)
151	            let stored = defaults.string(forKey: AppPreferenceKeys.menuBarOutageWarningText.rawValue)
152	            return stored ?? "⚠️"
153	        }
154	        set {
155	            withMutation(keyPath: \.menuBarOutageWarningText) {
156	                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarOutageWarningText.rawValue)
157	            }
158	        }
159	    }
160	
161	    public var chartConfigurations: [ChartConfiguration] {
162	        get {
163	            access(keyPath: \.chartConfigurations)
164	            guard let data = defaults.data(forKey: AppPreferenceKeys.chartConfigurations.rawValue) else {
165	                return []
166	            }
167	            do {
168	                return try JSONDecoder().decode([ChartConfiguration].self, from: data)
169	            } catch {
170	                Loggers.app.log(.error, "Failed to decode chartConfigurations from UserDefaults: \(error)")
171	                return []
172	            }
173	        }
174	        set {
175	            withMutation(keyPath: \.chartConfigurations) {
176	                do {
177	                    let data = try JSONEncoder().encode(newValue)
178	                    defaults.set(data, forKey: AppPreferenceKeys.chartConfigurations.rawValue)
179	                } catch {
180	                    Loggers.app.log(.error, "Failed to encode chartConfigurations to UserDefaults: \(error)")
181	                }
182	            }
183	        }
184	    }
185	
186	    public var chartConfigurationsInitialized: Bool {
187	        get { defaults.bool(forKey: AppPreferenceKeys.chartConfigurationsInitialized.rawValue) }
188	        set { defaults.set(newValue, forKey: AppPreferenceKeys.chartConfigurationsInitialized.rawValue) }
189	    }
190	
191	    public var ignoredAccounts: [IgnoredAccount] {
192	        get {
193	            access(keyPath: \.ignoredAccounts)
194	            guard let data = defaults.data(forKey: AppPreferenceKeys.ignoredAccounts.rawValue) else {
195	                return []
196	            }
197	            do {
198	                return try JSONDecoder().decode([IgnoredAccount].self, from: data)
199	            } catch {
200	                Loggers.app.log(.error, "Failed to decode ignoredAccounts from UserDefaults: \(error)")
201	                return []
202	            }
203	        }
204	        set {
205	            withMutation(keyPath: \.ignoredAccounts) {
206	                do {
207	                    let data = try JSONEncoder().encode(newValue)
208	                    defaults.set(data, forKey: AppPreferenceKeys.ignoredAccounts.rawValue)
209	                } catch {
210	                    Loggers.app.log(.error, "Failed to encode ignoredAccounts to UserDefaults: \(error)")
211	                }
212	            }
213	        }
214	    }
215	}
