217	// MARK: - In-memory test double
218	
219	/// Shared between production defaults-absent paths and test code.
220	@Observable
221	@MainActor
222	public final class InMemoryAppPreferences: AppPreferences {
223	    public var refreshInterval: RefreshInterval
224	    public var launchAtLogin: Bool
225	    public var logLevel: LogLevel
226	    public var menuBarSegments: [MenuBarSegmentConfig]
227	    public var menuBarSegmentsInitialized: Bool
228	    public var menuBarSeparator: String
229	    public var menuBarOutageWarningEnabled: Bool
230	    public var menuBarOutageWarningText: String
231	    public var chartConfigurations: [ChartConfiguration]
232	    public var chartConfigurationsInitialized: Bool
233	    public var ignoredAccounts: [IgnoredAccount]
234	
235	    public init(
236	        refreshInterval: RefreshInterval = .default,
237	        launchAtLogin: Bool = false,
238	        logLevel: LogLevel = .info,
239	        menuBarSegments: [MenuBarSegmentConfig] = [],
240	        menuBarSegmentsInitialized: Bool = false,
241	        menuBarSeparator: String = " | ",
242	        menuBarOutageWarningEnabled: Bool = true,
243	        menuBarOutageWarningText: String = "⚠️",
244	        chartConfigurations: [ChartConfiguration] = [],
245	        chartConfigurationsInitialized: Bool = false,
