import Foundation
import Observation

// MARK: - Protocol

/// Single source of truth for user-adjustable runtime behaviour.
/// Injectable so tests can swap in `InMemoryAppPreferences`.
@MainActor
public protocol AppPreferences: AnyObject, Observable, Sendable {
    var refreshInterval: RefreshInterval { get set }
    var launchAtLogin: Bool { get set }
    var logLevel: LogLevel { get set }
    var menuBarSegments: [MenuBarSegmentConfig] { get set }
    /// Tracks whether seeding has already run — distinguishes "fresh install"
    /// from "user deleted all segments." False on a brand-new UserDefaults suite.
    var menuBarSegmentsInitialized: Bool { get set }
    /// String inserted between adjacent segments in the menu bar label. Defaults to " | ".
    var menuBarSeparator: String { get set }
    /// When true, the menu bar prepends `menuBarOutageWarningText` while at least
    /// one vendor has an active outage. Defaults to true (opt-out).
    var menuBarOutageWarningEnabled: Bool { get set }
    /// Short label rendered before segments while any vendor has an active outage.
    /// Defaults to "⚠️".
    var menuBarOutageWarningText: String { get set }
    var chartConfigurations: [ChartConfiguration] { get set }
    /// Tracks whether chart seeding has already run so an intentionally empty
    /// configuration list is preserved after first initialization.
    var chartConfigurationsInitialized: Bool { get set }
    var ignoredAccounts: [IgnoredAccount] { get set }
}

// MARK: - UserDefaults-backed implementation

@Observable
@MainActor
public final class UserDefaultsAppPreferences: AppPreferences {
    private let defaults: UserDefaults

    public init(defaults: UserDefaults = .standard) {
        self.defaults = defaults
    }

    public var refreshInterval: RefreshInterval {
        get {
            access(keyPath: \.refreshInterval)
            let raw = defaults.integer(forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
            if raw == 0 { return .default }
            return RefreshInterval(clamping: raw)
        }
        set {
            withMutation(keyPath: \.refreshInterval) {
                defaults.set(newValue.seconds, forKey: AppPreferenceKeys.refreshIntervalSeconds.rawValue)
            }
        }
    }

    public var launchAtLogin: Bool {
        get {
            access(keyPath: \.launchAtLogin)
            return defaults.bool(forKey: AppPreferenceKeys.launchAtLogin.rawValue)
        }
        set {
            withMutation(keyPath: \.launchAtLogin) {
                defaults.set(newValue, forKey: AppPreferenceKeys.launchAtLogin.rawValue)
            }
        }
    }

    public var logLevel: LogLevel {
        get {
            access(keyPath: \.logLevel)
            let raw = defaults.string(forKey: AppPreferenceKeys.logLevel.rawValue) ?? ""
            if raw.isEmpty { return .info }
            return LogLevel.from(string: raw)
        }
        set {
            withMutation(keyPath: \.logLevel) {
                defaults.set(newValue.label.lowercased(), forKey: AppPreferenceKeys.logLevel.rawValue)
            }
        }
    }

    public var menuBarSegments: [MenuBarSegmentConfig] {
        get {
            // @Observable wraps stored properties; computed ones need manual tracking so
            // SwiftUI / withObservationTracking observers are notified on mutation.
            access(keyPath: \.menuBarSegments)
            guard let data = defaults.data(forKey: AppPreferenceKeys.menuBarSegments.rawValue) else {
                return []
            }
            do {
                return try JSONDecoder().decode([MenuBarSegmentConfig].self, from: data)
            } catch {
                Loggers.app.log(.error, "Failed to decode menuBarSegments from UserDefaults: \(error)")
                return []
            }
        }
        set {
            withMutation(keyPath: \.menuBarSegments) {
                do {
                    let data = try JSONEncoder().encode(newValue)
                    defaults.set(data, forKey: AppPreferenceKeys.menuBarSegments.rawValue)
                } catch {
                    Loggers.app.log(.error, "Failed to encode menuBarSegments to UserDefaults: \(error)")
                }
            }
        }
    }

    public var menuBarSegmentsInitialized: Bool {
        get { defaults.bool(forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
        set { defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSegmentsInitialized.rawValue) }
    }

    public var menuBarSeparator: String {
        get {
            access(keyPath: \.menuBarSeparator)
            let stored = defaults.string(forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
            return stored ?? " | "
        }
        set {
            withMutation(keyPath: \.menuBarSeparator) {
                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarSeparator.rawValue)
            }
        }
    }

    public var menuBarOutageWarningEnabled: Bool {
        get {
            access(keyPath: \.menuBarOutageWarningEnabled)
            // Default to enabled on a fresh install — but only if we've never persisted
            // an explicit value. UserDefaults.bool returns false for missing keys, so we
            // gate on a separate "initialized" flag to distinguish "never set" from
            // "explicitly disabled".
            if !defaults.bool(forKey: AppPreferenceKeys.menuBarOutageWarningEnabledInitialized.rawValue) {
                return true
            }
            return defaults.bool(forKey: AppPreferenceKeys.menuBarOutageWarningEnabled.rawValue)
        }
        set {
            withMutation(keyPath: \.menuBarOutageWarningEnabled) {
                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarOutageWarningEnabled.rawValue)
                defaults.set(true, forKey: AppPreferenceKeys.menuBarOutageWarningEnabledInitialized.rawValue)
            }
        }
    }

    public var menuBarOutageWarningText: String {
        get {
            access(keyPath: \.menuBarOutageWarningText)
            let stored = defaults.string(forKey: AppPreferenceKeys.menuBarOutageWarningText.rawValue)
            return stored ?? "⚠️"
        }
        set {
            withMutation(keyPath: \.menuBarOutageWarningText) {
                defaults.set(newValue, forKey: AppPreferenceKeys.menuBarOutageWarningText.rawValue)
            }
        }
    }

    public var chartConfigurations: [ChartConfiguration] {
        get {
            access(keyPath: \.chartConfigurations)
            guard let data = defaults.data(forKey: AppPreferenceKeys.chartConfigurations.rawValue) else {
                return []
            }
            do {
                return try JSONDecoder().decode([ChartConfiguration].self, from: data)
            } catch {
                Loggers.app.log(.error, "Failed to decode chartConfigurations from UserDefaults: \(error)")
                return []
            }
        }
        set {
            withMutation(keyPath: \.chartConfigurations) {
                do {
                    let data = try JSONEncoder().encode(newValue)
                    defaults.set(data, forKey: AppPreferenceKeys.chartConfigurations.rawValue)
                } catch {
                    Loggers.app.log(.error, "Failed to encode chartConfigurations to UserDefaults: \(error)")
                }
            }
        }
    }

    public var chartConfigurationsInitialized: Bool {
        get { defaults.bool(forKey: AppPreferenceKeys.chartConfigurationsInitialized.rawValue) }
        set { defaults.set(newValue, forKey: AppPreferenceKeys.chartConfigurationsInitialized.rawValue) }
    }

    public var ignoredAccounts: [IgnoredAccount] {
        get {
            access(keyPath: \.ignoredAccounts)
            guard let data = defaults.data(forKey: AppPreferenceKeys.ignoredAccounts.rawValue) else {
                return []
            }
            do {
                return try JSONDecoder().decode([IgnoredAccount].self, from: data)
            } catch {
                Loggers.app.log(.error, "Failed to decode ignoredAccounts from UserDefaults: \(error)")
                return []
            }
        }
        set {
            withMutation(keyPath: \.ignoredAccounts) {
                do {
                    let data = try JSONEncoder().encode(newValue)
                    defaults.set(data, forKey: AppPreferenceKeys.ignoredAccounts.rawValue)
                } catch {
                    Loggers.app.log(.error, "Failed to encode ignoredAccounts to UserDefaults: \(error)")
                }
            }
        }
    }
}

// MARK: - In-memory test double

/// Shared between production defaults-absent paths and test code.
@Observable
@MainActor
public final class InMemoryAppPreferences: AppPreferences {
    public var refreshInterval: RefreshInterval
    public var launchAtLogin: Bool
    public var logLevel: LogLevel
    public var menuBarSegments: [MenuBarSegmentConfig]
    public var menuBarSegmentsInitialized: Bool
    public var menuBarSeparator: String
    public var menuBarOutageWarningEnabled: Bool
    public var menuBarOutageWarningText: String
    public var chartConfigurations: [ChartConfiguration]
    public var chartConfigurationsInitialized: Bool
    public var ignoredAccounts: [IgnoredAccount]

    public init(
        refreshInterval: RefreshInterval = .default,
        launchAtLogin: Bool = false,
        logLevel: LogLevel = .info,
        menuBarSegments: [MenuBarSegmentConfig] = [],
        menuBarSegmentsInitialized: Bool = false,
        menuBarSeparator: String = " | ",
        menuBarOutageWarningEnabled: Bool = true,
        menuBarOutageWarningText: String = "⚠️",
        chartConfigurations: [ChartConfiguration] = [],
        chartConfigurationsInitialized: Bool = false,
        ignoredAccounts: [IgnoredAccount] = []
    ) {
        self.refreshInterval = refreshInterval
        self.launchAtLogin = launchAtLogin
        self.logLevel = logLevel
        self.menuBarSegments = menuBarSegments
        self.menuBarSegmentsInitialized = menuBarSegmentsInitialized
        self.menuBarSeparator = menuBarSeparator
        self.menuBarOutageWarningEnabled = menuBarOutageWarningEnabled
        self.menuBarOutageWarningText = menuBarOutageWarningText
        self.chartConfigurations = chartConfigurations
        self.chartConfigurationsInitialized = chartConfigurationsInitialized
        self.ignoredAccounts = ignoredAccounts
    }
}

