import Foundation

/// Semantic version of the app, parsed from `CFBundleShortVersionString` or a
/// release tag like `v1.2.3`. Comparison ignores pre-release and metadata
/// suffixes — releases tagged with build suffixes still compare numerically.
public struct AppVersion: Sendable, Hashable, Comparable, CustomStringConvertible {
    public let major: Int
    public let minor: Int
    public let patch: Int
    public let rawValue: String

    public init?(string: String) {
        let trimmed = string.hasPrefix("v") ? String(string.dropFirst()) : string
        let core = trimmed.split(whereSeparator: { $0 == "-" || $0 == "+" }).first.map(String.init) ?? trimmed
        let parts = core.split(separator: ".")
        guard parts.count >= 1, let major = Int(parts[0]) else { return nil }
        let minor = parts.count >= 2 ? Int(parts[1]) ?? 0 : 0
        let patch = parts.count >= 3 ? Int(parts[2]) ?? 0 : 0
        self.major = major
        self.minor = minor
        self.patch = patch
        self.rawValue = trimmed
    }

    public var description: String { rawValue }

    public static func < (lhs: AppVersion, rhs: AppVersion) -> Bool {
        if lhs.major != rhs.major { return lhs.major < rhs.major }
        if lhs.minor != rhs.minor { return lhs.minor < rhs.minor }
        return lhs.patch < rhs.patch
    }
}

import SwiftUI
import AIUsagesTrackersLib

struct UpdatesSettingsView: View {
    let preferences: any AppPreferences
    let updateState: UpdateState

    private static let lastCheckedFormatter: DateFormatter = {
        let f = DateFormatter()
        f.dateStyle = .medium
        f.timeStyle = .short
        return f
    }()

    var body: some View {
        let prefs = AppDelegate.sharedPreferences
        Form {
            Section("Automatic updates") {
                Toggle("Check for updates automatically", isOn: Binding(
                    get: { prefs.updatesAutoCheckEnabled },
                    set: { prefs.updatesAutoCheckEnabled = $0 }
                ))
                Text("When enabled, AI Usages Tracker checks GitHub for new releases at startup and every six hours.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }

            Section("Manual check") {
                HStack {
                    Button("Check now") {
                        Task {
                            await AppDelegate.sharedUpdateScheduler?.checkNow()
                        }
                    }
                    .disabled(updateState.phase == .checking)

                    if updateState.phase == .checking {
                        ProgressView().controlSize(.small).scaleEffect(0.7)
                    }
                    Spacer()
                    if let last = updateState.lastCheckedAt {
                        Text("Last checked \(Self.lastCheckedFormatter.string(from: last))")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                }
                if let pending = updateState.pendingUpdate {
                    Text("Version \(pending.version.rawValue) is available.")
                        .font(.caption)
                        .foregroundStyle(.green)
                } else if updateState.lastError != nil {
                    Text("Last check failed: \(updateState.lastError ?? "")")
                        .font(.caption)
                        .foregroundStyle(.red)
                } else if updateState.lastCheckedAt != nil {
                    Text("You are up to date.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }

            if !prefs.updatesDismissedVersions.isEmpty {
                Section("Skipped versions") {
                    ForEach(prefs.updatesDismissedVersions, id: \.self) { version in
                        HStack {
                            Text(version).font(.system(size: 12))
                            Spacer()
                            Button(role: .destructive) {
                                prefs.updatesDismissedVersions.removeAll { $0 == version }
                                updateState.dismissedVersions.remove(version)
                            } label: {
                                Image(systemName: "trash")
                            }
                            .buttonStyle(.borderless)
                        }
                    }
                }
            }
        }
        .formStyle(.grouped)
    }
}

import Foundation

public enum InstallationKind: Sendable, Equatable {
    /// Installed via Homebrew cask `ai-usages-tracker`.
    case homebrewCask
    /// Bundle lives outside any known package manager prefix — the user copied
    /// the .app manually (e.g. dragged into /Applications, or running ad-hoc).
    case manual
}

public struct InstallationInfo: Sendable, Equatable {
    public let kind: InstallationKind
    public let bundlePath: String

    public init(kind: InstallationKind, bundlePath: String) {
        self.kind = kind
        self.bundlePath = bundlePath
    }
}

/// Detects how the running app bundle was installed, so the installer can pick
/// the right upgrade path (Homebrew cask vs. direct zip replacement).
public actor InstallationDetector {
    private let bundlePath: String
    private let process: ProcessRunning
    private let fileManager: FileManager
    private let homebrewBinaryPaths: [String]

    public static let homebrewCaskName = "ai-usages-tracker"

    public init(
        bundlePath: String,
        process: ProcessRunning = FoundationProcessRunner(),
        fileManager: FileManager = .default,
        homebrewBinaryPaths: [String] = ["/opt/homebrew/bin/brew", "/usr/local/bin/brew"]
    ) {
        self.bundlePath = bundlePath
        self.process = process
        self.fileManager = fileManager
        self.homebrewBinaryPaths = homebrewBinaryPaths
    }

    public func detect() async -> InstallationInfo {
        guard let brewPath = firstExistingBrewPath() else {
            return InstallationInfo(kind: .manual, bundlePath: bundlePath)
        }
        // `brew --caskroom` returns the directory containing per-cask folders.
        // The cask owns artifacts under `<caskroom>/<name>/<version>/...`. If
        // the running bundle's resolved path lives under that subtree, we know
        // it was installed by Homebrew.
        let caskroom: String
        do {
            let result = try await process.run(
                executablePath: brewPath,
                arguments: ["--caskroom"],
                timeoutSeconds: 5
            )
            guard result.terminationStatus == 0, !result.timedOut else {
                return InstallationInfo(kind: .manual, bundlePath: bundlePath)
            }
            caskroom = String(decoding: result.stdout, as: UTF8.self)
                .trimmingCharacters(in: .whitespacesAndNewlines)
        } catch {
            return InstallationInfo(kind: .manual, bundlePath: bundlePath)
        }

        guard !caskroom.isEmpty else {
            return InstallationInfo(kind: .manual, bundlePath: bundlePath)
        }

        let resolved = resolveSymlinks(bundlePath)
        let caskPrefix = caskroom.hasSuffix("/") ? "\(caskroom)\(Self.homebrewCaskName)" : "\(caskroom)/\(Self.homebrewCaskName)"
        if resolved.hasPrefix(caskPrefix + "/") || resolved == caskPrefix {
            return InstallationInfo(kind: .homebrewCask, bundlePath: bundlePath)
        }
        return InstallationInfo(kind: .manual, bundlePath: bundlePath)
    }

    /// Exposed for the installer — returns the path of an existing brew binary
    /// or nil if Homebrew is not installed at the expected locations.
    public func brewExecutablePath() -> String? {
        firstExistingBrewPath()
    }

    private func firstExistingBrewPath() -> String? {
        homebrewBinaryPaths.first { fileManager.fileExists(atPath: $0) }
    }

    private func resolveSymlinks(_ path: String) -> String {
        URL(fileURLWithPath: path).resolvingSymlinksInPath().path
    }
}

import Foundation
import Observation

/// Observable holder used by the menu bar popover to display a banner when a
/// newer release is available, and to reflect "checking" / "installing" state.
@Observable
@MainActor
public final class UpdateState {
    public enum Phase: Sendable, Equatable {
        case idle
        case checking
        case installing
    }

    public private(set) var phase: Phase = .idle
    public private(set) var availableUpdate: AvailableUpdate?
    public private(set) var lastCheckedAt: Date?
    public private(set) var lastError: String?
    public private(set) var installationKind: InstallationKind?
    /// Versions the user explicitly chose to skip. Persisted in preferences so
    /// the banner stays dismissed across launches.
    public var dismissedVersions: Set<String>

    public init(dismissedVersions: Set<String> = []) {
        self.dismissedVersions = dismissedVersions
    }

    public func setChecking() {
        phase = .checking
        lastError = nil
    }

    public func setIdle(checkedAt: Date) {
        phase = .idle
        lastCheckedAt = checkedAt
    }

    public func setAvailable(_ update: AvailableUpdate?, kind: InstallationKind?, checkedAt: Date) {
        availableUpdate = update
        installationKind = kind
        lastCheckedAt = checkedAt
        phase = .idle
    }

    public func setError(_ message: String, at: Date) {
        phase = .idle
        lastError = message
        lastCheckedAt = at
    }

    public func setInstalling() {
        phase = .installing
    }

    public func dismissCurrent() {
        if let version = availableUpdate?.version.rawValue {
            dismissedVersions.insert(version)
        }
        availableUpdate = nil
    }

    /// Returns the available update only when the user hasn't dismissed it.
    public var pendingUpdate: AvailableUpdate? {
        guard let update = availableUpdate else { return nil }
        if dismissedVersions.contains(update.version.rawValue) { return nil }
        return update
    }
}

